"use client";

import { motion } from "framer-motion";
import { useState, useEffect } from "react";
import { useWallet } from "@solana/wallet-adapter-react";
import { ContentItem, lamportsToSol } from "@/lib/content";
import { useHasAccess, usePurchase } from "@/hooks/useSolStream";
import { Loader2, Lock, Play, Star } from "lucide-react";
import Link from "next/link";

interface Props {
    content: ContentItem;
}

export function ContentCard({ content }: Props) {
    const [mounted, setMounted] = useState(false);
    useEffect(() => setMounted(true), []);

    const { connected } = useWallet();
    const { hasAccess, loading: checkingAccess, refresh } = useHasAccess(content);
    const { purchase, purchasing, error } = usePurchase(content);
    const [showError, setShowError] = useState(false);

    const handleUnlock = async () => {
        const ok = await purchase();
        if (ok) {
            await refresh();
        } else {
            setShowError(true);
            setTimeout(() => setShowError(false), 4000);
        }
    };

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            whileHover={{ scale: 1.03 }}
            transition={{ duration: 0.3 }}
            className="group relative rounded-2xl overflow-hidden bg-[#12121f] border border-white/5 shadow-xl cursor-pointer"
        >
            {/* Thumbnail */}
            <div className="relative h-52 overflow-hidden">
                <img
                    src={content.thumbnail}
                    alt={content.title}
                    className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                />
                {/* Gradient overlay */}
                <div className="absolute inset-0 bg-gradient-to-t from-[#12121f] via-transparent to-transparent" />

                {/* Rating badge */}
                <div className="absolute top-3 right-3 flex items-center gap-1 bg-black/60 backdrop-blur-sm rounded-full px-2 py-1 text-xs text-yellow-400 font-semibold">
                    {content.rating}
                </div>

                {/* Access indicator */}
                {hasAccess && (
                    <div className="absolute top-3 left-3 flex items-center gap-1 bg-violet-600/80 backdrop-blur-sm rounded-full px-2 py-1 text-xs text-white font-semibold">
                        <Play size={10} fill="white" /> Unlocked
                    </div>
                )}
            </div>

            {/* Info */}
            <div className="p-4 space-y-2">
                <div className="flex items-start justify-between gap-2">
                    <h3 className="text-white font-bold text-base leading-tight">
                        {content.title}
                    </h3>
                    <span className="text-violet-400 font-bold text-sm whitespace-nowrap">
                        {lamportsToSol(content.priceLamports)}
                    </span>
                </div>
                <div className="flex items-center gap-2 text-xs text-gray-400">
                    <span>{content.year}</span>
                    <span className="w-1 h-1 rounded-full bg-gray-600" />
                    <span>{content.duration}</span>
                    <span className="w-1 h-1 rounded-full bg-gray-600" />
                    <span className="text-violet-300">{content.genre}</span>
                </div>
                <p className="text-gray-400 text-xs leading-relaxed line-clamp-2">
                    {content.description}
                </p>

                {/* Error message */}
                {showError && error && (
                    <p className="text-red-400 text-xs">{error}</p>
                )}

                {/* Action button — only fully render after hydration to avoid SSR mismatch */}
                <div className="pt-1">
                    {!mounted ? (
                        /* Stable server-rendered placeholder */
                        <button
                            disabled
                            className="w-full bg-white/5 text-gray-500 font-semibold text-sm py-2.5 rounded-xl cursor-not-allowed flex items-center justify-center gap-2"
                        >
                            <Lock size={14} />
                            Connect wallet to unlock
                        </button>
                    ) : checkingAccess ? (
                        <div className="flex items-center justify-center py-2">
                            <Loader2 className="animate-spin text-violet-400" size={18} />
                        </div>
                    ) : hasAccess ? (
                        <Link href={`/watch/${content.id.toString()}`}>
                            <button className="w-full bg-violet-600 hover:bg-violet-500 text-white font-semibold text-sm py-2.5 rounded-xl transition-all duration-200 flex items-center justify-center gap-2">
                                <Play size={14} fill="white" />
                                Watch Now
                            </button>
                        </Link>
                    ) : connected ? (
                        <button
                            onClick={handleUnlock}
                            disabled={purchasing}
                            className="w-full bg-gradient-to-r from-violet-600 to-fuchsia-600 hover:from-violet-500 hover:to-fuchsia-500 disabled:opacity-50 text-white font-semibold text-sm py-2.5 rounded-xl transition-all duration-200 flex items-center justify-center gap-2"
                        >
                            {purchasing ? (
                                <Loader2 className="animate-spin" size={14} />
                            ) : (
                                <Lock size={14} />
                            )}
                            {purchasing ? "Processing..." : `Unlock for ${lamportsToSol(content.priceLamports)}`}
                        </button>
                    ) : (
                        <button
                            disabled
                            className="w-full bg-white/5 text-gray-500 font-semibold text-sm py-2.5 rounded-xl cursor-not-allowed flex items-center justify-center gap-2"
                        >
                            <Lock size={14} />
                            Connect wallet to unlock
                        </button>
                    )}
                </div>
            </div>

            {/* Glow effect on hover */}
            <div className="absolute inset-0 rounded-2xl bg-violet-500/0 group-hover:bg-violet-500/5 transition-all duration-300 pointer-events-none" />
        </motion.div>
    );
}
