import { PublicKey, Connection, clusterApiUrl } from "@solana/web3.js";
import { PROGRAM_ID } from "./idl";

export const SOLANA_NETWORK = "devnet";
export const RPC_ENDPOINT = clusterApiUrl(SOLANA_NETWORK);
export const PROGRAM_PUBLIC_KEY = new PublicKey(PROGRAM_ID);

export const connection = new Connection(RPC_ENDPOINT, "confirmed");

/** Derive the PDA for a ContentRecord. */
export function deriveContentPDA(contentId: bigint): [PublicKey, number] {
    const idBuffer = Buffer.alloc(8);
    idBuffer.writeBigUInt64LE(contentId);
    return PublicKey.findProgramAddressSync(
        [Buffer.from("content"), idBuffer],
        PROGRAM_PUBLIC_KEY
    );
}

/** Derive the PDA for a UserAccess account. */
export function deriveUserAccessPDA(
    buyer: PublicKey,
    contentId: bigint
): [PublicKey, number] {
    const idBuffer = Buffer.alloc(8);
    idBuffer.writeBigUInt64LE(contentId);
    return PublicKey.findProgramAddressSync(
        [Buffer.from("access"), buyer.toBuffer(), idBuffer],
        PROGRAM_PUBLIC_KEY
    );
}

/** Check whether a UserAccess PDA account exists on-chain for a buyer+contentId. */
export async function checkAccess(
    buyer: PublicKey,
    contentId: bigint
): Promise<boolean> {
    try {
        const [pda] = deriveUserAccessPDA(buyer, contentId);
        const info = await connection.getAccountInfo(pda);
        return info !== null && info.data.length > 0;
    } catch {
        return false;
    }
}
